import "./App.css";
import {Outlet, NavLink} from "react-router";

function App() {

  return (
    <>

    <nav>
      <ul>
        <li><NavLink to="/">Home</NavLink></li>
        <li><NavLink to="/about">About</NavLink></li>
        <li><NavLink to="/todo">ToDo</NavLink></li>
        <li><NavLink to="/users">Users</NavLink></li>
      </ul>
    </nav>
    <Outlet />
    </>
  );
}

export default App;
